// COMPLETE, COMPILABLE C code
#include <stdio.h>
#define MAXN 505
int dp1[MAXN][MAXN], dp2[MAXN][MAXN], grid[MAXN][MAXN];
int main() {
    int T, N, i, j;
    scanf("%d", &T);
    while (T--) {
        scanf("%d", &N);
        for (i = 1; i <= N; i++) {
            for (j = 1; j <= i; j++) {
                scanf("%d", &grid[i][j]);
            }
        }
        // Initialize dp arrays
        for (i = 1; i <= N; i++) {
            for (j = 1; j <= N; j++) {
                dp1[i][j] = dp2[i][j] = 0;
            }
        }
        // Fill up dp1 array
        dp1[1][1] = grid[1][1];
        for (i = 2; i <= N; i++) {
            for (j = 1; j <= i; j++) {
                if (j == 1) {
                    dp1[i][j] = dp1[i - 1][j] + grid[i][j];
                } else if (j == i) {
                    dp1[i][j] = dp1[i - 1][j - 1] + grid[i][j];
                } else {
                    dp1[i][j] = grid[i][j] + (dp1[i - 1][j - 1] > dp1[i - 1][j] ? dp1[i - 1][j - 1] : dp1[i - 1][j]);
                }
            }
        }
        // Fill up dp2 array
        dp2[N][N] = grid[N][N];
        for (i = N - 1; i >= 1; i--) {
            for (j = N; j >= 1; j--) {
                if (j == N) {
                    dp2[i][j] = dp2[i + 1][j] + grid[i][j];
                } else if (j == i) {
                    dp2[i][j] = dp2[i + 1][j + 1] + grid[i][j];
                } else {
                    dp2[i][j] = grid[i][j] + (dp2[i + 1][j + 1] > dp2[i + 1][j] ? dp2[i + 1][j + 1] : dp2[i + 1][j]);
                }
            }
        }
        // Calculate the final answer
        int ans = dp1[N][1] + dp2[N][1] - grid[N][1];
        printf("%d\n", ans);
    }
    return 0;
}

