                for (int j = 1; j <= N; j++) {
                    dp1[i][j] = dp2[i][j] = 0;
                }
            }
            // Fill up dp1 array
            dp1[1][1] = grid[1][1];
            for (int i = 2; i <= N; i++) {
                for (int j = 1; j <= i; j++) {
                    if (j == 1) {
                        dp1[i][j] = dp1[i - 1][j] + grid[i][j];
                    } else if (j == i) {
                        dp1[i][j] = dp1[i - 1][j - 1] + grid[i][j];
                    } else {
                        dp1[i][j] = grid[i][j] + (dp1[i - 1][j - 1] > dp1[i - 1][j] ? dp1[i - 1][j - 1] : dp1[i - 1][j]);
                    }
                }
            }
            // Fill up dp2 array
            dp2[N][N] = grid[N][N];
            for (int i = N - 1; i >= 1; i--) {
                for (int j = N; j >= 1; j--) {
                    if (j == N) {
                        dp2[i][j] = dp2[i + 1][j] + grid[i][j];
                    } else if (j == i) {
                        dp2[i][j] = dp2[i + 1][j + 1] + grid[i][j];
                    } else {
                        dp2[i][j] = grid[i][j] + (dp2[i + 1][j + 1] > dp2[i + 1][j] ? dp2[i + 1][j + 1] : dp2[i + 1][j]);
                    }
                }
            }
            // Calculate the final answer
            int ans = dp1[N][1] + dp2[N][1] - grid[N][1];
            System.out.println(ans);
        }
    }
}

